x : PGame
h : x ⧏ 0
⊢ x⁻¹ =
    -match -x with
      | mk α r L R =>
        let l' := { i // 0 < L i };
        let L' := fun i => L ↑i;
        let IHl' := fun i => (L ↑i).inv';
        let IHr := fun i => (R i).inv';
        mk (InvTy l' r false) (InvTy l' r true) (invVal L' R IHl' IHr) (invVal L' R IHl' IHr)

